import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import '../../../../app/theme/app_colors.dart'; import '../../../../app/theme/app_spacing.dart'; import '../../../../app/theme/app_text_styles.dart'; import '../../../../core/utils/result.dart'; import '../../../../shared/widgets/buttons/primary_button.dart'; import '../../../../shared/widgets/cards/app_card.dart'; import '../../../../shared/widgets/layout/app_top_bar.dart'; import '../../../../shared/widgets/layout/screen.dart'; import '../../domain/models/offer.dart'; import '../../domain/repositories/offer_repository.dart';
final class OffersPage extends StatefulWidget { const OffersPage({required this.orderId, required this.repository, super.key}); final String orderId; final OfferRepository repository; @override State<OffersPage> createState()=>_OffersPageState(); }
final class _OffersPageState extends State<OffersPage> { late final Future<Result<List<Offer>>> _future = widget.repository.getOffers(widget.orderId); @override Widget build(BuildContext context)=>Screen(padding: EdgeInsets.zero, appBar: AppTopBar(title:'Technician Offers', subtitle:'Updating live', onBack:()=>context.pop()), child: FutureBuilder<Result<List<Offer>>>(future:_future,builder:(context,snapshot){if(snapshot.connectionState==ConnectionState.waiting)return const Center(child:CircularProgressIndicator(color:AppColors.primary)); final result=snapshot.data; if(result is ErrorResult<List<Offer>>)return Center(child:Text(result.failure.message,style:AppTextStyles.bodyMedium.copyWith(color:AppColors.error))); if(result is Success<List<Offer>>){if(result.value.isEmpty)return const Center(child:Text('No offers yet')); return ListView.separated(padding:const EdgeInsets.all(AppSpacing.space20),itemCount:result.value.length,separatorBuilder:(context,index)=>const SizedBox(height:AppSpacing.space12),itemBuilder:(context,index)=>_OfferCard(offer:result.value[index],onAccept:()=>_accept(result.value[index])));} return const Center(child:Text('Unable to load offers'));})); Future<void> _accept(Offer offer) async {final result=await widget.repository.acceptOffer(offer.id); if(!mounted)return; if(result is ErrorResult<Offer>){ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text(result.failure.message)));return;} context.pop();}}
final class _OfferCard extends StatelessWidget { const _OfferCard({required this.offer,required this.onAccept}); final Offer offer; final VoidCallback onAccept; @override Widget build(BuildContext context)=>AppCard(child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(offer.masterName??'Technician',style:AppTextStyles.titleMedium),const SizedBox(height:AppSpacing.space8),Text('Arrival: ${offer.arrivalTime}',style:AppTextStyles.bodySmall),const SizedBox(height:AppSpacing.space4),Text('${offer.price.toStringAsFixed(0)} ₸',style:AppTextStyles.headlineMedium),if(offer.comment case final comment?)... [const SizedBox(height:AppSpacing.space8),Text(comment,style:AppTextStyles.bodySmall)],const SizedBox(height:AppSpacing.space12),PrimaryButton(label:'Accept offer',onPressed:offer.status=='ACTIVE'?onAccept:null)]));}
